class Solution:
    def countLargestGroup(self, n: int) -> int:
        groups = {}
        for i in range(1, n + 1):
            digit_sum = sum(int(digit) for digit in str(i))
            if digit_sum in groups:
                groups[digit_sum] += 1
            else:
                groups[digit_sum] = 1
        max_size = max(groups.values())
        return list(groups.values()).count(max_size)
```
